classDiagram(name = "OnlineShopModel") {
    val customer = classOf(name = "Customer") {
        attribute(name = "name", type = "String")
    }
    val address = classOf(name = "Address") {
        attribute(name = "street", type = "String")
        attribute(name = "city", type = "String")
    }
    val shoppingCart = classOf(name = "ShoppingCart") {
        // No specific attributes for shopping cart requested
    }
    val product = classOf(name = "Product") {
        attribute(name = "name", type = "String")
        attribute(name = "price", type = "Double")
    }
    val lineItem = classOf(name = "LineItem") {
        attribute(name = "quantity", type = "Int")
    }
    val order = classOf(name = "Order") {
        attribute(name = "status", type = "String") // Represents created, paid, shipped, cancelled
        attribute(name = "orderDate", type = "String")
    }

    // Customer must register at least one delivery address; addresses only exist in context of customer
    association(source = customer, target = address) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1..*"); role = "deliveryAddresses" }
    }

    // Each customer has at most one active shopping cart
    association(source = customer, target = shoppingCart) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..1"); role = "activeCart" }
    }

    // Shopping cart is made up of line items
    association(source = shoppingCart, target = lineItem) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "items" }
    }

    // Each line item references exactly one product
    association(source = lineItem, target = product) {
        source { multiplicity(spec = "0..*") }
        target { multiplicity(spec = "1"); role = "product" }
    }

    // A customer can place any number of orders
    association(source = customer, target = order) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "orders" }
    }

    // Order is created containing line items from the cart
    association(source = order, target = lineItem) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1..*"); role = "lineItems" }
    }
}

