classDiagram(name = "HospitalManagement") {
    val person = classOf(name = "Person") {
        isAbstract = true
        attribute(name = "name", type = "String")
        attribute(name = "dateOfBirth", type = "String")
    }
    val patient = classOf(name = "Patient") {
        extends(general = person)
        attribute(name = "bloodType", type = "String")
    }
    val doctor = classOf(name = "Doctor") {
        extends(general = person)
    }
    val nursingStaff = classOf(name = "NursingStaff") {
        extends(general = person)
    }
    val ward = classOf(name = "Ward")
    val appointment = classOf(name = "Appointment")
    val treatmentStep = classOf(name = "TreatmentStep")

    // Patient is assigned to exactly one ward
    association(source = ward, target = patient) {
        source { multiplicity(spec = "0..*"); role = "patients" }
        target { multiplicity(spec = "1"); role = "assignedWard" }
    }

    // Ward is staffed by at least one nurse
    association(source = ward, target = nursingStaff) {
        source { multiplicity(spec = "1..*"); role = "staffedByNurses" }
        target { multiplicity(spec = "0..*"); role = "worksInWards" }
    }

    // Appointment connects exactly one patient
    association(source = patient, target = appointment) {
        source { multiplicity(spec = "0..*"); role = "appointments" }
        target { multiplicity(spec = "1"); role = "forPatient" }
    }

    // Appointment connects exactly one doctor
    association(source = doctor, target = appointment) {
        source { multiplicity(spec = "0..*"); role = "appointments" }
        target { multiplicity(spec = "1"); role = "withDoctor" }
    }

    // Appointment contains several treatment steps that cannot exist without it (composition)
    association(source = appointment, target = treatmentStep) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "treatmentSteps" }
    }
}

