sequenceDiagram(name = "Checkout Process") {
    val customer = lifeline(name = "Customer") { isActor = true }
    val shop = lifeline(name = "Shop")
    val checkoutService = lifeline(name = "CheckoutService")
    val paymentGateway = lifeline(name = "PaymentGateway")
    val database = lifeline(name = "Database")

    message(from = customer, to = shop, label = "initiateCheckout()")
    message(from = shop, to = checkoutService, label = "verifyPaymentDetails()")
    message(from = checkoutService, to = paymentGateway, label = "checkPaymentDetails()")

    alt {
        branch(guard = "[payment valid]") {
            reply(from = paymentGateway, to = checkoutService, label = "detailsValid")
            message(from = checkoutService, to = database, label = "saveOrder()")
            reply(from = database, to = checkoutService, label = "orderSaved")
            message(from = checkoutService, to = paymentGateway, label = "processPayment()")
            reply(from = paymentGateway, to = checkoutService, label = "paymentProcessed")
            reply(from = checkoutService, to = shop, label = "checkoutSuccess")
            reply(from = shop, to = customer, label = "displaySuccess()")
        }
        branch(guard = "[payment invalid]") {
            reply(from = paymentGateway, to = checkoutService, label = "detailsInvalid")
            reply(from = checkoutService, to = shop, label = "checkoutRejected(errorMessage)")
            reply(from = shop, to = customer, label = "displayError(errorMessage)")
        }
    }
}

sequenceDiagram(name = "ClientDataRequestFlow") {
    val client = lifeline(name = "Client") { isActor = true }
    val apiGateway = lifeline(name = "API Gateway")
    val rateLimiter = lifeline(name = "Rate Limiter")
    val backendService = lifeline(name = "Backend Service")

    // First attempt: Quota exhausted
    message(from = client, to = apiGateway, label = "Request Data via API")
    message(from = apiGateway, to = rateLimiter, label = "Check Client Quota")
    reply(from = rateLimiter, to = apiGateway, label = "Quota Exhausted")
    message(from = apiGateway, to = client, label = "Reject: Too Many Requests")

    // Client waits (backoff) and retries
    message(from = client, to = apiGateway, label = "Retry Request Data (Attempt 2)")
    message(from = apiGateway, to = rateLimiter, label = "Check Client Quota")
    reply(from = rateLimiter, to = apiGateway, label = "Quota Available")

    // Quota available: Forward to backend
    message(from = apiGateway, to = backendService, label = "Forward Request to Backend")
    reply(from = backendService, to = apiGateway, label = "Return Data")
    reply(from = apiGateway, to = client, label = "Return Data to Client")
}

