sequenceDiagram(name = "CollisionAvoidanceSystem") {
    val camera = lifeline(name = "Camera Sensor") { isActor = true }
    val radar = lifeline(name = "Radar Sensor") { isActor = true }
    val fusion = lifeline(name = "Fusion Unit")
    val assistant = lifeline(name = "Emergency Braking Assistant")
    val driver = lifeline(name = "Driver") { isActor = true }
    val control = lifeline(name = "Control Unit")
    val log = lifeline(name = "Diagnostic Log")

    message(from = camera, to = fusion, label = "measurement data")
    message(from = radar, to = fusion, label = "measurement data")
    message(from = fusion, to = assistant, label = "collision risk with TTC")

    // Scenario: TTC < critical threshold
    message(from = assistant, to = driver, label = "Acoustic Warning (TTC < threshold)")
    message(from = assistant, to = control, label = "Initiate Autonomous Braking (TTC < threshold)")
    message(from = assistant, to = control, label = "Adjust brake pressure repeatedly")
    reply(from = control, to = assistant, label = "Vehicle stationary")
    message(from = assistant, to = log, label = "Record braking event in diagnostic log")

    // Scenario: TTC >= critical threshold (Alternatively, for parallel or mutually exclusive paths)
    // The prompt's example structure does not provide constructs for 'if/else' branches,
    // so these are represented as separate sequential messages with clarifying labels.
    message(from = assistant, to = driver, label = "Distance Warning (TTC >= threshold)")
